declare @name nvarchar(4000), @header nvarchar(512) select @header = case when @bc_theo = 0 then case when @@language = 'V' then N'Tài khoản' else 'Account' end when @bc_theo = 1 then case when @@language = 'V' then N'Phí' else 'Expense' end when @bc_theo = 2 then case when @@language = 'V' then N'Bộ phận' else 'Department' end when @bc_theo = 3 then case when @@language = 'V' then N'Vụ việc' else 'Job' end end select @name = case when @bc_theo = 0 then (select case when @@language = 'V' then ten_tk else ten_tk2 end from dmtk where tk = @tk) when @bc_theo = 1 then (select case when @@language = 'V' then ten_phi else ten_phi2 end from dmphi where ma_phi = @ma_phi) when @bc_theo = 2 then (select case when @@language = 'V' then ten_bp else ten_bp2 end from dmbp where ma_bp = @ma_bp) when @bc_theo = 3 then (select case when @@language = 'V' then ten_vv else ten_vv2 end from dmvv where ma_vv = @ma_vv) end select 'this._header = ''' + replace(replace(isnull(@header, ''), '\', '\\'), '''', '\''') + '''; this._Name = ''' + replace(replace(isnull(@name, ''), '\', '\\'), '''', '\''') + ''';this._queryFilterString = ''' + replace(replace(@@queryString, '\', '\\'), '''', '\''') + ''';init$GridQuery$(this);' as message return
