declare @queryWhereClause nvarchar(4000), @queryFormClause nvarchar(4000) select @queryFormClause = 'left join dmkh b with(nolock, index(pk_dmkh)) on a.ma_kh = b.ma_kh' select @queryWhereClause = case when @bc_theo = 0 then 'a.tk = ''' + replace(@tk, '''', '''''') + '''' when @bc_theo = 1 then 'a.ma_phi = ''' + replace(@ma_phi, '''', '''''') + '''' when @bc_theo = 2 then 'a.ma_bp = ''' + replace(@ma_bp, '''', '''''') + '''' when @bc_theo = 3 then 'a.ma_vv = ''' + replace(@ma_vv, '''', '''''') + '''' end if @nh_theo <> '' begin select @queryWhereClause = case when @nh_theo = 0 then @queryWhereClause + case when @bc_theo = 2 then '' else ' and a.ma_bp = ''' + replace(@ma_bp, '''', '''''') + '''' end when @nh_theo = 1 then @queryWhereClause + case when @bc_theo = 1 then '' else ' and a.ma_phi = ''' + replace(@ma_phi, '''', '''''') + '''' end when @nh_theo = 2 then @queryWhereClause + case when @bc_theo = 0 then '' else ' and a.tk = ''' + replace(@tk, '''', '''''') + '''' end when @nh_theo = 3 then @queryWhereClause + case when @bc_theo = 3 then '' else ' and a.ma_vv = ''' + replace(@ma_vv, '''', '''''') + '''' end when @nh_theo in (4, 7) then @queryWhereClause + case when @bc_theo in (0, 3) then ' and a.ma_bp = ''' + replace(@ma_bp, '''', '''''') + ''' and a.ma_phi = ''' + replace(@ma_phi, '''', '''''') + '''' when @bc_theo = 1 then ' and a.ma_bp = ''' + replace(@ma_bp, '''', '''''') + '''' when @bc_theo = 2 then ' and a.ma_phi = ''' + replace(@ma_phi, '''', '''''') + '''' end when @nh_theo in (5, 10) then @queryWhereClause + case when @bc_theo = 0 then ' and a.ma_bp = ''' + replace(@ma_bp, '''', '''''') + '''' when @bc_theo in (1, 3) then ' and a.ma_bp = ''' + replace(@ma_bp, '''', '''''') + ''' and a.tk = ''' + replace(@tk, '''', '''''') + '''' when @bc_theo = 2 then ' and a.tk = ''' + replace(@tk, '''', '''''') + '''' end when @nh_theo in (6, 13) then @queryWhereClause + case when @bc_theo in (0, 1) then ' and a.ma_bp = ''' + replace(@ma_bp, '''', '''''') + ''' and a.ma_vv = ''' + replace(@ma_vv, '''', '''''') + '''' when @bc_theo = 2 then ' and a.ma_vv = ''' + replace(@ma_vv, '''', '''''') + '''' when @bc_theo = 3 then ' and a.ma_bp = ''' + replace(@ma_bp, '''', '''''') + '''' end when @nh_theo in (8, 11) then @queryWhereClause + case when @bc_theo = 0 then ' and a.ma_phi = ''' + replace(@ma_phi, '''', '''''') + '''' when @bc_theo = 1 then ' and a.tk = ''' + replace(@tk, '''', '''''') + '''' when @bc_theo in (2, 3) then ' and a.ma_phi = ''' + replace(@ma_phi, '''', '''''') + ''' and a.tk = ''' + replace(@tk, '''', '''''') + '''' end when @nh_theo in (9, 14) then @queryWhereClause + case when @bc_theo in (0, 2) then ' and a.ma_phi = ''' + replace(@ma_phi, '''', '''''') + ''' and a.ma_vv = ''' + replace(@ma_vv, '''', '''''') + '''' when @bc_theo = 1 then ' and a.ma_vv = ''' + replace(@ma_vv, '''', '''''') + '''' when @bc_theo = 3 then ' and a.ma_phi = ''' + replace(@ma_phi, '''', '''''') + '''' end when @nh_theo in (12, 15) then @queryWhereClause + case when @bc_theo in (1, 2) then ' and a.tk = ''' + replace(@tk, '''', '''''') + ''' and a.ma_vv = ''' + replace(@ma_vv, '''', '''''') + '''' when @bc_theo = 0 then ' and a.ma_vv = ''' + replace(@ma_vv, '''', '''''') + '''' when @bc_theo = 3 then ' and a.tk = ''' + replace(@tk, '''', '''''') + '''' end end end if not(@nh_theo in (1, 4, 7, 8, 9, 11, 14) or @bc_theo = 1) begin if @nh_phi1 + @nh_phi2 + @nh_phi3 <> '' select @queryFormClause = @queryFormClause + ' left join dmphi c with(nolock) on a.ma_phi = c.ma_phi' if @nh_phi1 <> '' select @queryWhereClause = @queryWhereClause + ' and c.nh_phi1 like ''' + replace(@nh_phi1, '''', '''''') + '%''' if @nh_phi2 <> '' select @queryWhereClause = @queryWhereClause + ' and c.nh_phi2 like ''' + replace(@nh_phi2, '''', '''''') + '%''' if @nh_phi3 <> '' select @queryWhereClause = @queryWhereClause + ' and c.nh_phi3 like ''' + replace(@nh_phi3, '''', '''''') + '%''' end
if @ds_tk <> '' and @bc_theo <> 0 and @nh_theo in(0, 1, 3, 5) select @queryWhereClause = @queryWhereClause + ' and ' + dbo.FastBusiness$Function$System$GetAccountFilter('a.tk', 'inlist', @ds_tk)
select @queryWhereClause = @queryWhereClause + case when @no_co = 1 then ' and (ps_no + ps_no_nt <> 0' + case when @ds_tk2 = '' then ')' else ' or (ps_co + ps_co_nt <> 0 and ' + dbo.FastBusiness$Function$System$GetAccountFilter('a.tk_du', 'notinlist', @ds_tk2) + '))' end when @no_co = 2 then ' and (ps_co + ps_co_nt <> 0' + case when @ds_tk2 = '' then ')' else ' or (ps_no + ps_no_nt <> 0 and ' + dbo.FastBusiness$Function$System$GetAccountFilter('a.tk_du', 'notinlist', @ds_tk2) + '))' end end
