&JavascriptReportInit; /* <flatten type="Javascript"> */ function init$GridQuery$(g) { var a = g._queryFilterString.split(String.fromCharCode(253)), x = a[6], i = (x == '0' ? 0 : (x == '1' ? 1 : (x == '2' ? 2: 3))); g._alterTitle = [null, [['%h', g._header, true], ['%c', a[i], true], ['%s', g._Name, true], ['%d1', formatDateView(a[4]), true], ['%d2', formatDateView(a[5]), true]]]; g._hiddenFields = [ {Fields: 'ps_no_nt, ps_co_nt', Value: (a[11] == '10')}, {Fields: 'tk', Value: (x == '0')}, {Fields: 'ma_vv', Value: (x == '3')} ]; } /* </flatten> */
